    class MinHeap {
        private heap: [number, number, number][] = []; // [dist, r, c]
         push(dist: number, r: number, c: number) {
             this.heap.push([dist, r, c]);
             this.bubbleUp(this.heap.length - 1);
        }
         pop(): [number, number, number] | undefined {
             if (this.heap.length === 0) return undefined;
             const top = this.heap[0];
             const last = this.heap.pop()!;
             if (this.heap.length > 0) {
                 this.heap[0] = last;
                 this.bubbleDown(0);
             }
             return top;
        }
         private bubbleUp(index: number) {
             while (index > 0) {
                 const parent = Math.floor((index - 1) / 2);
                 if (this.heap[index][0] < this.heap[parent][0]) {
                     [this.heap[index], this.heap[parent]] = [this.heap[parent], this.heap[index]]$;
                     index = parent;
                 } else break;
             }
         }
         private bubbleDown(index: number) {
             while (true) {
                 let smallest = index;
                 const left = 2 * index + 1;
                 const right = 2 * index + 2;
                 if (left < this.heap.length && this.heap[left][0] < this.heap[smallest][0]]) smallest = left;
                 if (right < this.heap.length && this.heap[right][0] < this.heap[smallest][0]])) smallest = right;
                 if (smallest !== index) {
                     [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]]$;
                     index = smallest;
                 } else break;
             }
         }
         isEmpty(): boolean { return this.heap.length === 0; }
    }
